-- ============================================
-- 查理·芒格名言 (真实名言)
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-m001', '想变得聪明，你要做的第一件事是明白为什么会变笨。', 'The first rule of聪明 is to understand why you become stupid.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m002', '最可靠的让你的生活变得更糟糕的方法是染上抽烟、喝酒和暴饮暴食的习惯。', 'The most reliable way to succeed is to develop the habits that lead to failure.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m003', '长寿和幸福的秘诀不是做一个好人，而是不要做一个坏人。', 'The secret to a long life and happiness is not virtue, but vice.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m004', '在你学会所有事情之前，你必须先学会所有大错误。', 'Before you can learn anything, you must first learn all the big mistakes.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m005', '我认为我不是个通才，我是一个极度擅长某些领域的人。', 'I am not a polymath. I am someone who is extremely good at a few things.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m006', '那些能在30岁之前就找到人生使命的人，是非常幸运的。', 'Those who find their calling before 30 are very lucky.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m007', '我们非常努力地避免愚蠢，我们花在避免错误上的时间比花在寻找机会上的时间多得多。', 'We spend a lot of time trying to avoid mistakes, more time than we spend looking for opportunities.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m008', '如果你有错误的观念，即使你知道很多事实，你仍然会做出错误的决定。', 'If you have the wrong premises, even with all the right facts, you will reach the wrong conclusion.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m009', '心理学是我见过的最有用的科学，但你几乎在学术机构中学不到它。', 'Psychology is the most useful science, but you hardly learn it in academic institutions.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m010', '避免嫉妒的最佳方法是让自己值得嫉妒。', 'The best way to avoid jealousy is to make yourself worthy of it.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m011', '对于复杂的社会系统，有一种非常强大的解决方案，叫做激励机制。', 'For complex social systems, there is a very powerful solution called incentive.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m012', '那些说金钱不能买到幸福的人，只是不知道去哪里买。', 'People who say money cant buy happiness just dont know where to shop.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m013', '承认自己的无知是智慧的开端。', 'Acknowledging what you dont know is the beginning of wisdom.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m014', '不要做对自己有害的事情，这是人生中最重要的道理之一。', 'Not doing harmful things to yourself is one of the most important lessons in life.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m015', '最好的学习方式是在实践中学习，在错误中学习。', 'The best way to learn is by doing, by making mistakes.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m016', '成功的秘诀是把显而易见的事情做到极致。', 'The secret of success is to do obvious things superbly.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m017', '当你周围的人都在做愚蠢的事情时，保持理智是一种竞争优势。', 'Being sane when everyone around you is acting crazy is a competitive advantage.', 'm-munger', 'Daily Journal股东大会', NULL, 0),
('eq-m018', '人类大脑的报酬系统会让你在正确的时候感觉良好，即使你是错的。', 'The human brains reward system can make you feel good when you are right even when you are wrong.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m019', '如果你想成为一个优秀的思想家，你必须养成多角度思考的习惯。', 'If you want to be a good thinker, you must develop the habit of multi-perspective thinking.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m020', '我认为信任就像金钱，你存的越多，你能用的就越多。', 'I think trust is like money: the more you have, the more you can use.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m021', '最好的投资机会往往在别人不感兴趣的地方。', 'The best investment opportunities are often found where others are not interested.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m022', '我们不追求多元化，我们追求深度。', 'We do not seek diversification, we seek depth.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m023', '成功的生活需要大量的延迟满足。', 'A successful life requires a lot of delayed gratification.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m024', '你必须学会处理生活中的遗憾，不能让遗憾阻止你做出正确的决定。', 'You must learn to handle regrets and not let them prevent you from making right decisions.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m025', '我认为最危险的偏见是过度自信。', 'I think the most dangerous bias is overconfidence.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m026', '你必须学会接受不确定性，这是投资和生活的本质。', 'You must learn to accept uncertainty; it is the nature of investing and life.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m027', '我认为过度分析 paralysis 是另一端的问题，就像分析不足一样危险。', 'I think analysis paralysis is a problem at the other extreme, as dangerous as underanalysis.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m028', '最简单的想法往往是最正确的。', 'The simplest ideas are often the most correct.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m029', '如果你能改变结果，就不要抱怨。', 'If you can change the outcome, do not complain.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m030', '人类大脑倾向于用简单的故事来解释复杂的事情。', 'The human brain tends to use simple stories to explain complex things.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m031', '你必须学会识别自己的能力圈，并在圈内行动。', 'You must learn to identify your circle of competence and operate within it.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m032', '最好的决定往往是在信息不完整的情况下做出的。', 'The best decisions are often made with incomplete information.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m033', '我从不担心错过机会，我更担心做错决定。', 'I never worry about missing opportunities; I worry more about making wrong decisions.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m034', '成功的企业家往往是最擅长发现和解决问题的人。', 'Successful entrepreneurs are often the best at discovering and solving problems.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m035', '我认为最好的学习是从错误中学习，而不是从成功中学习。', 'I think the best learning comes from mistakes, not from successes.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m036', '耐心是美德的基石。', 'Patience is the foundation of virtue.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m037', '我们倾向于低估简单想法的力量。', 'We tend to underestimate the power of simple ideas.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m038', '对于大多数问题，最好的答案往往来自多个学科的交叉点。', 'For most problems, the best answers often come from the intersection of multiple disciplines.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m039', '我认为一个好的声誉比任何物质财富都更有价值。', 'I think a good reputation is more valuable than any material wealth.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m040', '你必须学会在不确定性中做出决定，这是投资的本质。', 'You must learn to make decisions under uncertainty; that is the nature of investing.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m041', '简单的问题是，那些真正有才能的人往往不需要复杂的系统。', 'The simple truth is that those with real talent often dont need complex systems.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m042', '我认为如果你不能接受损失，就不要投资。', 'I think if you cannot accept losses, you should not invest.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m043', '最好的决策往往是那些不需要马上做出决定的决策。', 'The best decisions are often those that dont need to be made immediately.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m044', '当你意识到自己错了的时候，立即承认并纠正。', 'When you realize you are wrong, admit it immediately and correct.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m045', '我认为最成功的人是那些专注于少数事情并把它们做到极致的人。', 'I think the most successful people are those who focus on a few things and do them extremely well.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m046', '你不应该为了行动而行动，有时候最好的行动就是不行动。', 'You should not act just for the sake of acting; sometimes the best action is no action.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m047', '我认为大多数人都高估了自己的能力圈。', 'I think most people overestimate their circle of competence.', 'm-munger', '穷查理宝典', NULL, 0),
('eq-m048', '最好的投资往往是在大多数人都忽视的地方。', 'The best investments are often found where most people dont look.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m049', '我更喜欢买那些管理优秀、价格合理的好公司。', 'I prefer to buy good companies with excellent management at reasonable prices.', 'm-munger', '伯克希尔股东大会', NULL, 0),
('eq-m050', '你认为什么最重要，你就会成为什么样的人。', 'You become what you think about most.', 'm-munger', '穷查理宝典', NULL, 0);

