-- ============================================
-- 本杰明·格雷厄姆名言
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-g001', '投资操作是基于全面的分析，旨在确保本金安全和满意回报。不满足这些要求的操作就是投机。', 'Investment operation is one that promises safety of principal and a satisfactory return. Operations not meeting these requirements are speculative.', 'm-graham', '证券分析', 1934, 0),
('eq-g002', '聪明的投资者是一个现实主义者，他只买入那些提供安全边际的证券。', 'A smart investor is a realist who only buys securities that offer a margin of safety.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g003', '股票市场短期是投票机，长期是称重机，最终会反映公司的内在价值。', 'In the short run the market is a voting machine, in the long run a weighing machine. It will ultimately reflect the intrinsic value of companies.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g004', '一个投资者如果在他的投资决策中依赖他人的建议，他最终将一无所获。', 'An investor who relies on others for advice will end up with nothing.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g005', '最聪明的投资方式，是化繁为简。', 'The smartest investment is to simplify.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g006', '投资的本质是以低于价值的价格购买证券，这样当价格回归价值时，你就获得了安全边际。', 'The essence of investing is buying securities at less than their value, so that when the price returns to value, you have a margin of safety.', 'm-graham', '证券分析', 1934, 0),
('eq-g007', '不要在意股票的短期价格波动，要关注股票的长期价值。', 'Do not focus on short-term price fluctuations; focus on the long-term value of stocks.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g008', '普通股可以作为一种长期投资，只要购买时价格合理，并且公司有良好的发展前景。', 'Common stock can be a long-term investment if purchased at reasonable prices and the company has good prospects.', 'm-graham', '证券分析', 1934, 0),
('eq-g009', '投资的关键是控制风险，而不是追求高回报。', 'The key to investing is controlling risk, not pursuing high returns.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g010', '当市场下跌时，投资者不应该恐慌，而应该看到机会。', 'When the market falls, investors should not panic but see opportunities.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g011', '防御型投资者的投资组合应该包括高质量的债券和多样化的大型蓝筹股。', 'A defensive investors portfolio should include high-quality bonds and diversified large-cap blue-chip stocks.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g012', '成长股投资策略更适合积极型投资者，而不是防御型投资者。', 'Growth stock investment strategies are more suitable for aggressive investors than for defensive investors.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g013', '债券的收益是有限的，但股票的收益是无限的。', 'Bond returns are limited, but stock returns are unlimited.', 'm-graham', '证券分析', 1934, 0),
('eq-g014', '投资者应该把注意力放在公司的盈利能力上，而不是股价的波动上。', 'Investors should focus on the companys profitability, not stock price fluctuations.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g015', '好的投资是那些在购买时就能让你安心睡觉的投资。', 'Good investments are those that let you sleep well at night when you buy them.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g016', '不要试图在最低点买入，在最高点卖出，这是投资者的致命错误。', 'Do not try to buy at the bottom and sell at the top; that is a fatal mistake for investors.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g017', '投资的回报取决于你支付的价格，低价买入是成功投资的关键。', 'Investment returns depend on the price you pay; buying at low prices is the key to successful investing.', 'm-graham', '证券分析', 1934, 0),
('eq-g018', '市场先生的情绪不应该影响你的投资决策，你应该利用他的情绪。', 'Mr. Markets emotions should not affect your investment decisions; you should exploit his emotions.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g019', '股票的内在价值是由公司未来现金流量的现值决定的。', 'The intrinsic value of a stock is determined by the present value of the companys future cash flows.', 'm-graham', '证券分析', 1934, 0),
('eq-g020', '一个保守的投资者应该把大部分资金投入债券，只把一小部分投入股票。', 'A conservative investor should put most of their funds in bonds and only a small portion in stocks.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g021', '投资成功的关键是耐心和纪律，而不是智慧。', 'The key to investment success is patience and discipline, not intelligence.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g022', '如果你不能承受股价下跌50%，就不应该持有股票。', 'If you cannot withstand a 50% decline in stock price, you should not own stocks.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g023', '证券分析的价值在于帮助你发现被低估的证券。', 'The value of security analysis is in helping you find undervalued securities.', 'm-graham', '证券分析', 1934, 0),
('eq-g024', '一个公司如果长期没有盈利，就不应该被投资。', 'A company that has not been profitable for a long time should not be invested in.', 'm-graham', '证券分析', 1934, 0),
('eq-g025', '投资者应该定期检查他们的投资组合，确保投资目标没有改变。', 'Investors should regularly review their portfolios to ensure investment objectives have not changed.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g026', '分散投资是降低风险的有效方法，但不应该以牺牲质量为代价。', 'Diversification is an effective way to reduce risk, but should not come at the expense of quality.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g027', '价值投资的核心是寻找价格低于内在价值的证券。', 'The core of value investing is finding securities priced below their intrinsic value.', 'm-graham', '证券分析', 1934, 0),
('eq-g028', '投资者应该学会区分投资和投机，投机不会带来长期成功。', 'Investors should learn to distinguish between investing and speculating; speculation does not lead to long-term success.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g029', '长期来看，股票市场的回报与公司的盈利增长是一致的。', 'In the long run, stock market returns are consistent with company earnings growth.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g030', '不要把所有的鸡蛋放在一个篮子里，但也不要放在太多的篮子里。', 'Do not put all your eggs in one basket, but do not put them in too many baskets either.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g031', '投资于高质量公司的债券是保守投资策略的核心。', 'Investing in high-quality corporate bonds is the core of a conservative investment strategy.', 'm-graham', '证券分析', 1934, 0),
('eq-g032', '股票投资应该基于公司的基本面，而不是市场的短期波动。', 'Stock investing should be based on company fundamentals, not short-term market fluctuations.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g033', '投资的本质是以低于价值的价格买入证券，等待价格回归价值。', 'The essence of investing is buying securities below their value and waiting for prices to return to value.', 'm-graham', '证券分析', 1934, 0),
('eq-g034', '防御型投资者应该避免高风险的投资，如期权、期货等。', 'Defensive investors should avoid high-risk investments such as options and futures.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g035', '好的投资策略应该简单明了，容易执行。', 'A good investment strategy should be simple and easy to execute.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g036', '投资者应该关注公司的盈利能力、资产价值和财务稳定性。', 'Investors should focus on company profitability, asset value and financial stability.', 'm-graham', '证券分析', 1934, 0),
('eq-g037', '如果你不能在股价下跌时继续持有，那么一开始就不应该买入。', 'If you cannot hold on when the stock price falls, you should not have bought it in the first place.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g038', '证券的内在价值与市场价格无关，它是由公司的基本价值决定的。', 'The intrinsic value of a security has nothing to do with its market price; it is determined by the companys fundamental value.', 'm-graham', '证券分析', 1934, 0),
('eq-g039', '投资者应该把注意力放在长期价值上，而不是短期利润上。', 'Investors should focus on long-term value, not short-term profits.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g040', '最成功的投资往往是在别人都不看好的时候做出的。', 'The most successful investments are often made when no one else is optimistic.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g041', '投资于那些有稳定现金流的公司，比投资于那些只有增长潜力的公司更安全。', 'Investing in companies with stable cash flows is safer than investing in companies with only growth potential.', 'm-graham', '证券分析', 1934, 0),
('eq-g042', '投资者应该学会在市场恐慌时买入，在市场贪婪时卖出。', 'Investors should learn to buy when the market panics and sell when the market is greedy.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g043', '股票投资的核心是找到那些价格低于价值的公司。', 'The core of stock investing is finding companies whose prices are below their value.', 'm-graham', '证券分析', 1934, 0),
('eq-g044', '投资者应该避免盲目跟风，要独立思考。', 'Investors should avoid blindly following the crowd and think independently.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g045', '一个公司的账面价值是投资者可以依赖的底线。', 'A companys book value is a bottom line that investors can rely on.', 'm-graham', '证券分析', 1934, 0),
('eq-g046', '投资成功的关键是控制情绪，理性决策。', 'The key to investment success is controlling emotions and making rational decisions.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g047', '好的投资是那些即使在不利情况下也能保护你本金的投资。', 'Good investments are those that protect your principal even in adverse conditions.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g048', '投资者应该学会耐心等待，等待合适的价格出现。', 'Investors should learn to wait patiently for the right price.', 'm-graham', '聪明的投资者', 1949, 0),
('eq-g049', '债券投资比股票投资更安全，但回报也更低。', 'Bond investing is safer than stock investing, but the returns are also lower.', 'm-graham', '证券分析', 1934, 0),
('eq-g050', '最聪明的投资方式是以低于清算价值的价格买入公司。', 'The smartest investment is to buy a company at less than its liquidation value.', 'm-graham', '证券分析', 1934, 0);

