-- ============================================
-- 彼得·林奇名言
-- ============================================

INSERT OR IGNORE INTO quotes (id, content_cn, content_en, master_id, source, source_year, is_featured) VALUES
('eq-l001', '在你的一生中，你会发现股票是比债券或储蓄账户更好的投资。', 'Over your investment lifetime, you will find stocks are a better investment than bonds or savings accounts.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l002', '如果你有十年的投资视野，就不需要在短期内做出决定。', 'If you have a ten-year investment horizon, you do not need to make short-term decisions.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l003', '业余投资者比专业投资者有优势，因为他们可以投资于任何他们了解的公司。', 'Individual investors have an advantage over professional investors because they can invest in any company they understand.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l004', '关注你所在行业的公司，这些是你最可能了解的公司。', 'Focus on companies in your industry; these are the ones you are most likely to understand.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l005', '当你逛街的时候，注意那些生意兴隆的商店，这可能是投资机会。', 'When you shop, notice which stores are busy; this could be an investment opportunity.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l006', '投资于你熟悉的公司，而不是追逐热门股票。', 'Invest in companies you are familiar with, not in hot stocks.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l007', '长期持有股票是积累财富的最有效方式之一。', 'Holding stocks for the long term is one of the most effective ways to build wealth.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l008', '如果你在股票下跌时恐慌性地卖出，你就不应该持有股票。', 'If you panic and sell when stocks fall, you should not own stocks.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l009', '关注公司的基本面，而不是股票价格的日常波动。', 'Focus on company fundamentals, not daily stock price movements.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l010', '找到下一个十倍股比找到下一个微软更容易。', 'Finding the next ten-bagger is easier than finding the next Microsoft.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l011', '不要试图预测利率或经济走势，专注于公司本身。', 'Do not try to predict interest rates or economic trends; focus on the company itself.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l012', '投资于有成长潜力的小公司，但要小心风险。', 'Invest in small companies with growth potential, but be careful of the risks.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l013', '在决定是否卖出股票之前，先问自己：我现在会买这只股票吗？', 'Before deciding to sell a stock, ask yourself: would I buy this stock now?', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l014', '不要因为股价便宜就买一只坏公司的股票。', 'Do not buy a bad companys stock just because the price is cheap.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l015', '公司的债务水平是评估风险的重要因素。', 'A companys debt level is an important factor in assessing risk.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l016', '一个公司的竞争优势来自于其独特的产品或服务。', 'A companys competitive advantage comes from its unique products or services.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l017', '投资于那些回购自己股票的公司，这是对未来的信心信号。', 'Invest in companies that buy back their own shares; this is a signal of confidence in the future.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l018', '关注公司的现金流，而不是会计利润。', 'Focus on cash flow, not accounting profits.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l019', '股票市场会在你需要钱的时候恰恰下跌。', 'The stock market will decline just when you need money.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l020', '不要因为别人都在买就跟着买，要有独立判断。', 'Do not buy just because everyone else is buying; have independent judgment.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l021', '投资于那些有稳定股息派发历史的公司。', 'Invest in companies with a stable history of dividend payments.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l022', '小公司比大公司更有增长潜力，但也更有风险。', 'Small companies have more growth potential than large companies, but also more risk.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l023', '了解你投资的公司，知道它在做什么生意。', 'Know the company you invest in and understand what business it is in.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l024', '不要把所有的钱都投入股票市场，要保留一些现金。', 'Do not put all your money in the stock market; keep some cash.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l025', '当你发现一个好的投资机会时，不要犹豫。', 'When you find a good investment opportunity, do not hesitate.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l026', '关注公司的管理层，优秀的管理层能创造优秀的公司。', 'Focus on company management; excellent management creates excellent companies.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l027', '如果你持有一只股票五年，你就不需要担心短期的市场波动。', 'If you hold a stock for five years, you do not need to worry about short-term market fluctuations.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l028', '投资于那些正在转型的公司，这往往是最大的机会。', 'Invest in companies that are transforming; this is often the biggest opportunity.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l029', '在股票市场上，钱是赚来的，不是想出来的。', 'In the stock market, money is earned, not thought up.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l030', '不要因为股票的名称好听就买，要看公司的实际业务。', 'Do not buy stocks because the name sounds good; look at the actual business.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l031', '一个公司如果有持续的盈利增长，就是一个好的投资标的。', 'A company with consistent earnings growth is a good investment candidate.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l032', '在熊市中寻找机会，在牛市中保持冷静。', 'Look for opportunities in bear markets and stay calm in bull markets.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l033', '投资于那些有强大品牌优势的公司。', 'Invest in companies with strong brand advantages.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l034', '不要试图在最低点买入，只要买的便宜就行。', 'Do not try to buy at the very bottom; just buy cheap enough.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l035', '关注公司的市场份额增长，这是公司竞争力的体现。', 'Focus on market share growth; this reflects company competitiveness.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l036', '如果一只股票让你睡不着觉，就卖掉它。', 'If a stock keeps you up at night, sell it.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l037', '投资于那些有稳定客户群的公司。', 'Invest in companies with stable customer bases.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l038', '股票投资应该是你生活的一部分，而不是全部。', 'Stock investing should be part of your life, not all of it.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l039', '在投资之前，做足功课，了解你要投资的公司。', 'Before investing, do your homework and understand the company you want to invest in.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l040', '不要因为一只股票便宜就买，要因为它有价值才买。', 'Do not buy a stock because it is cheap; buy it because it is valuable.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l041', '关注公司的创新能力，这是长期竞争力的来源。', 'Focus on company innovation capability; this is the source of long-term competitiveness.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l042', '投资于那些有全球化业务的公司，可以分散地域风险。', 'Invest in companies with global businesses to diversify geographic risk.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l043', '如果你在股票市场上感到恐惧，就退出市场。', 'If you feel fear in the stock market, get out of the market.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l044', '不要把投资决策建立在别人的建议上。', 'Do not base investment decisions on others advice.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l045', '一个公司的资产负债表是评估其健康状况的重要工具。', 'A companys balance sheet is an important tool for assessing its health.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l046', '投资于那些有定价权的公司。', 'Invest in companies with pricing power.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l047', '在股票市场上，最重要的不是你赚了多少，而是你活了下来。', 'In the stock market, the most important thing is not how much you made, but that you survived.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l048', '关注那些有重复性收入的公司，这种收入模式更稳定。', 'Focus on companies with recurring revenue; this income pattern is more stable.', 'm-lynch', '战胜华尔街', 1993, 0),
('eq-l049', '不要试图在短期内快速致富，这通常会导致失败。', 'Do not try to get rich quickly in the short term; this usually leads to failure.', 'm-lynch', '彼得·林奇的成功投资', 1989, 0),
('eq-l050', '投资于那些有良好企业文化的公司。', 'Invest in companies with good corporate culture.', 'm-lynch', '战胜华尔街', 1993, 0);

